const items = $input.all();
const item = items[0].json;
const isTelegram = item.message !== undefined;

let result;
if (isTelegram) {
  result = {
    source: 'telegram',
    userId: String(item.message.from.id),
    chatId: item.message.chat.id,
    message: item.message.text || '',
    name: item.message.from.first_name || 'Cliente'
  };
} else {
  result = {
    source: 'whatsapp',
    userId: item.From,
    chatId: item.From,
    message: item.Body || '',
    name: item.ProfileName || 'Cliente'
  };
}

return [{json: result}];
